191→            ...prev,
192→            name: v,
193→          }))
194→        }
195→        placeholder="e.g. Email Signature"
196→        error={errors.name}
197→        autoFocus
198→      />
199→      <FormTextField
200→        label="Keyword"
201→        value={form.keyword}
202→        onChange={v =>
203→          setForm(prev => ({
204→            ...prev,
205→            keyword: v,
206→          }))
207→        }
208→        placeholder="e.g. !sig"
209→        description="Type this to expand the snippet"
210→      />
211→      <FormDropdown
212→        label="Category"
213→        value={form.category}
214→        onChange={v => {
215→          if (isSnippetCategory(v)) {
216→            setForm(prev => ({
217→              ...prev,
218→              category: v,
219→            }));
220→          }
221→        }}
222→        options={FORM_CATEGORY_OPTIONS}
223→        placeholder="Select a category"
224→      />
225→      <FormTagPicker
226→        label="Tags"
227→        value={form.tags}
228→        onChange={v =>
229→          setForm(prev => ({
230→            ...prev,
231→            tags: v,
232→          }))
233→        }
234→        options={FORM_TAG_OPTIONS}
235→        placeholder="Add tags..."
236→        description="Categorize your snippet with tags"
237→      />
238→      <FormTextArea
239→        label="Snippet"
240→        value={form.snippet}
241→        onChange={v =>
242→          setForm(prev => ({
243→            ...prev,
244→            snippet: v,
245→          }))
246→        }
247→        placeholder="Enter your snippet content..."
248→        error={errors.snippet}
249→        rows={5}
250→      />
251→    </Form>
252→  );
253→}
