482→      }
483→      setSubView('list');
484→      setEditingSnippet(undefined);
485→    },
486→    [
487→      subView,
488→      editingSnippet,
489→      showHUD,
490→    ],
491→  );
492→
493→  const toggleActions = useCallback(() => {
494→    setActionsOpen(prev => !prev);
495→  }, []);
496→
497→  const closeActions = useCallback(() => {
498→    setActionsOpen(false);
499→  }, []);
500→
501→  const handleEscape = useCallback(() => {
502→    if (subView !== 'list') {
503→      setSubView('list');
