518→  useKeyboardShortcut(
519→    {
520→      key: 'c',
521→      meta: true,
522→    },
523→    handleCopy,
524→    {
525→      enabled: subView === 'list',
526→    },
527→  );
528→  useKeyboardShortcut(
529→    {
530→      key: 'n',
531→      meta: true,
532→    },
533→    handleCreate,
534→    {
535→      enabled: subView === 'list',
536→    },
537→  );
538→  useKeyboardShortcut(
539→    {
540→      key: 'e',
541→      meta: true,
542→    },
543→    handleEdit,
544→    {
545→      enabled: subView === 'list',
546→    },
547→  );
548→  useKeyboardShortcut(
549→    {
550→      key: 'Backspace',
551→      meta: true,
552→    },
553→    handleDelete,
554→    {
555→      enabled: subView === 'list',
556→    },
557→  );
558→  useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
559→    enabled: subView !== 'list',
560→    preventDefault: false,
