562→
563→  const dropdownSections: DropdownSection[] = useMemo(
564→    () => [
565→      {
566→        title: 'Actions',
567→        actions: [
568→          {
569→            label: 'Insert',
570→            shortcut: <Kbd keys={['↵']} />,
571→            onClick: handleInsert,
572→          },
573→          {
574→            label: 'Copy',
575→            shortcut: (
576→              <Kbd
577→                keys={[
578→                  '⌘',
579→                  'C',
580→                ]}
581→              />
582→            ),
583→            onClick: handleCopy,
584→          },
585→          {
586→            label: 'Edit',
587→            shortcut: (
588→              <Kbd
589→                keys={[
590→                  '⌘',
591→                  'E',
592→                ]}
593→              />
594→            ),
595→            onClick: handleEdit,
596→          },
597→          {
598→            label: 'Create Snippet',
599→            shortcut: (
600→              <Kbd
601→                keys={[
602→                  '⌘',
603→                  'N',
604→                ]}
605→              />
606→            ),
607→            onClick: handleCreate,
608→          },
609→        ],
610→      },
611→      {
612→        title: 'Danger Zone',
613→        actions: [
614→          {
615→            label: 'Delete',
616→            shortcut: (
617→              <Kbd
618→                keys={[
619→                  '⌘',
620→                  '⌫',
621→                ]}
622→              />
623→            ),
624→            onClick: handleDelete,
625→          },
626→        ],
627→      },
628→    ],
629→    [
630→      handleInsert,
631→      handleCopy,
632→      handleEdit,
633→      handleCreate,
634→      handleDelete,
635→    ],
636→  );
637→
638→  const activeDescendantId =
639→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
640→
641→  if (subView !== 'list') {
642→    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
643→    return (
