263→          {
264→            label: 'Commands',
265→            value: 'commands',
266→          },
267→          {
268→            label: 'Applications',
269→            value: 'applications',
270→          },
271→        ],
272→      },
273→    ],
274→    [],
275→  );
276→
277→  const colorFilterSections: SearchDropdownSection[] = useMemo(
278→    () => [
279→      {
280→        options: [
281→          {
282→            label: 'All Colors',
283→            value: 'all',
284→          },
285→        ],
286→      },
287→      {
288→        title: 'Category',
