291→            label: 'Warm',
292→            value: 'warm',
293→          },
294→          {
295→            label: 'Cool',
296→            value: 'cool',
297→          },
298→          {
299→            label: 'Neutral',
300→            value: 'neutral',
301→          },
302→        ],
303→      },
304→    ],
305→    [],
306→  );
307→
308→  useEffect(() => {
309→    if (nav.stackDepth === 0) {
310→      setQuery('');
311→      setFilterValue('all');
312→      setColorFilterValue('all');
313→      setSelectedIndex(0);
314→      setActionsOpen(false);
