528→                setQuickLookOpen(prev => !prev);
529→              }
530→            },
531→          },
532→        ],
533→      },
534→      {
535→        title: 'Copy Actions',
536→        actions: [
537→          {
538→            label: 'Copy Name',
539→            shortcut: (
540→              <Kbd
541→                keys={[
542→                  '⌘',
543→                  'C',
544→                ]}
545→              />
546→            ),
547→            onClick: () => {
548→              if (selectedItem) {
549→                showHUD({
550→                  icon: <CheckIcon />,
551→                  title: 'Copied to Clipboard',
552→                });
553→              }
554→            },
555→          },
556→          {
557→            label: 'Copy As...',
558→            submenu: [
559→              {
560→                actions: [
561→                  {
562→                    label: 'Copy as Markdown',
563→                    onClick: () => {
564→                      if (selectedItem) {
565→                        showHUD({
566→                          icon: <CheckIcon />,
567→                          title: 'Copied as Markdown',
568→                        });
569→                      }
570→                    },
571→                  },
572→                  {
573→                    label: 'Copy as JSON',
574→                    onClick: () => {
575→                      if (selectedItem) {
576→                        showHUD({
577→                          icon: <CheckIcon />,
578→                          title: 'Copied as JSON',
579→                        });
580→                      }
581→                    },
582→                  },
583→                  {
584→                    label: 'Copy as Plain Text',
585→                    onClick: () => {
586→                      if (selectedItem) {
587→                        showHUD({
588→                          icon: <CheckIcon />,
589→                          title: 'Copied as Plain Text',
590→                        });
591→                      }
592→                    },
593→                  },
594→                ],
595→              },
596→            ],
597→          },
598→        ],
599→      },
600→      {
601→        title: 'Danger Zone',
602→        actions: [
603→          {
604→            label: 'Delete',
605→            shortcut: (
606→              <Kbd
