651→                  style: 'cancel',
652→                  onAction: () => {},
653→                },
654→              });
655→            },
656→          },
657→        ],
658→      },
659→    ],
660→    [
661→      selectedItem,
662→      showToast,
663→      showHUD,
664→      confirmAlert,
665→    ],
666→  );
667→
668→  const activeDescendantId =
669→    viewType === 'root' && allItems.length > 0
670→      ? `list-item-${selectedIndex}`
671→      : viewType === 'grid' && filteredColors.length > 0
672→        ? `grid-item-${selectedIndex}`
673→        : undefined;
674→
675→  const navDirectionClass =
676→    nav.direction === 'push'
677→      ? ' command-palette__nav-view--push'
678→      : nav.direction === 'pop'
679→        ? ' command-palette__nav-view--pop'
680→        : '';
681→
682→  const contextLabel =
683→    nav.breadcrumbs.length > 0
684→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
685→      : 'Raycast';
686→
687→  function renderCurrentView() {
688→    const entry = nav.currentEntry;
689→    if (!entry) return null;
690→
691→    switch (entry.data.type) {
692→      case 'clipboard':
693→        return <ClipboardHistoryView />;
694→      case 'snippets':
695→        return <SnippetManagerView />;
696→      case 'grid':
697→        return (
698→          <ColorPickerView
699→            key={colorFilterValue}
700→            colors={filteredColors}
701→            onActiveIndexChange={handleActiveIndexChange}
702→            onAction={handleGridAction}
703→          />
704→        );
705→      case 'detail':
706→        return <DetailView item={entry.data.item} />;
707→    }
708→  }
709→
710→  const isFullView = viewType === 'clipboard' || viewType === 'snippets';
711→
712→  return (
713→    <NavigationContextProvider value={nav}>
714→      <CommandPalette isLoading>
715→        {!isFullView && (
716→          <SearchBar
717→            value={query}
718→            onChange={handleQueryChange}
719→            activeDescendantId={activeDescendantId}
720→            breadcrumbs={
721→              nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
722→            }
723→            dropdown={
724→              viewType === 'root' ? (
725→                <SearchDropdown
