728→                  onChange={handleFilterChange}
729→                />
730→              ) : viewType === 'grid' ? (
731→                <SearchDropdown
732→                  sections={colorFilterSections}
733→                  value={colorFilterValue}
734→                  onChange={handleColorFilterChange}
735→                />
736→              ) : undefined
737→            }
738→          />
739→        )}
740→        {isFullView && nav.currentEntry ? (
741→          <div
742→            key={nav.navKey}
743→            className={`command-palette__nav-view${navDirectionClass}`}
