745→            {renderCurrentView()}
746→          </div>
747→        ) : nav.currentEntry ? (
748→          <div
749→            key={nav.navKey}
750→            className={`command-palette__nav-view${navDirectionClass}`}
751→          >
752→            <div className="command-palette__body">
753→              <div className="command-palette__list-container">
754→                {renderCurrentView()}
755→              </div>
756→            </div>
757→          </div>
758→        ) : (
759→          <div
760→            className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
761→          >
762→            <div className="command-palette__list-container">
763→              {allItems.length === 0 ? (
764→                <EmptyState
765→                  icon={<SearchIcon />}
766→                  title="No Results"
767→                  description="Try a different search term"
768→                />
769→              ) : (
770→                <List
771→                  itemCount={allItems.length}
772→                  onActiveIndexChange={handleActiveIndexChange}
773→                  onAction={handleDrillIn}
774→                >
775→                  {(() => {
776→                    let globalIndex = 0;
777→                    return filtered.map(section => (
778→                      <ListSection key={section.title} title={section.title}>
779→                        {section.items.map(item => {
780→                          const idx = globalIndex++;
781→                          return (
782→                            <ListItem
783→                              key={item.id}
784→                              index={idx}
785→                              title={item.title}
786→                              subtitle={item.subtitle}
787→                              icon={item.icon}
788→                              accessories={item.accessories}
789→                            />
790→                          );
791→                        })}
792→                      </ListSection>
793→                    ));
794→                  })()}
795→                </List>
796→              )}
797→            </div>
798→            {detail && (
799→              <Detail
800→                markdown={detail.markdown}
801→                metadata={
802→                  detail.metadata ? (
803→                    <DetailMetadata>
804→                      {detail.metadata.map(renderMetadataEntry)}
805→                    </DetailMetadata>
806→                  ) : undefined
807→                }
808→              />
809→            )}
810→          </div>
811→        )}
812→        {!isFullView && (
813→          <ActionPanel
814→            contextLabel={contextLabel}
815→            actions={[
816→              {
817→                label: 'Open',
818→                shortcut: <Kbd keys={['↵']} />,
819→              },
820→              {
821→                label: 'Actions',
822→                shortcut: (
823→                  <Kbd
824→                    keys={[
825→                      '⌘',
826→                      'K',
827→                    ]}
828→                  />
829→                ),
830→                onClick: toggleActions,
831→              },
832→            ]}
833→            dropdownOpen={actionsOpen}
834→            dropdownSections={dropdownSections}
835→            onDropdownClose={closeActions}
836→          />
837→        )}
838→        {!isFullView && quickLookOpen && selectedItem?.detail && (
839→          <QuickLook title={selectedItem.title} onClose={closeQuickLook}>
840→            <Detail
841→              markdown={selectedItem.detail.markdown}
842→              metadata={
843→                selectedItem.detail.metadata ? (
844→                  <DetailMetadata>
845→                    {selectedItem.detail.metadata.map(renderMetadataEntry)}
846→                  </DetailMetadata>
847→                ) : undefined
848→              }
849→            />
850→          </QuickLook>
851→        )}
852→        {!isFullView && alertState && (
853→          <Alert
854→            title={alertState.title}
855→            message={alertState.message}
856→            icon={alertState.icon}
857→            primaryAction={alertState.primaryAction}
858→            dismissAction={alertState.dismissAction}
859→            onDismiss={dismissAlert}
860→          />
861→        )}
862→        <ToastContainer toasts={toasts} onDismiss={hideToast} />
863→        {!isFullView && <HUDContainer items={hudItems} />}
864→      </CommandPalette>
865→    </NavigationContextProvider>
866→  );
867→}
