                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
                            role="option"
                            aria-selected={isActive}
                            aria-label={emoji.name}
                            data-emoji-index={idx}
                            onClick={() => {
                              setActiveIndex(idx);
                              handleCopyEmoji(emoji);
                            }}
                            onMouseEnter={() => setActiveIndex(idx)}
                          >
                            {emoji.char}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ));
              })()}
            </div>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Emoji"
        actions={[
          {
            label: selectedEmoji
              ? `Copy ${selectedEmoji.char}`
              : 'Copy Emoji',
            shortcut: <Kbd keys={['↵']} />,
          },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      <HUDContainer items={hudItems} />
    </>
  );
}

