  const addToRecent = useCallback((char: string) => {
    setRecentChars(prev => {
      const next = [
        char,
        ...prev.filter(c => c !== char),
      ].slice(0, MAX_RECENT);
      saveRecentEmojis(next);
      return next;
    });
  }, []);

