              const prevSectionEnd = sectionStart - 1;
              const prevInfo = getSectionInfo(prevSectionEnd);
              if (!prevInfo) return prev;
              const prevSectionRows = Math.ceil(
                prevInfo.sectionLength / COLUMNS,
              );
