const COLUMNS = 6;
const RECENTLY_USED_KEY = 'emoji-picker-recent';
const MAX_RECENT = 12;

function CopyHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M3.5 8.5L6.5 11.5L12.5 4.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
